267	// ensureSelfSignedCert returns paths to a self-signed cert/key in dir,
268	// generating them if they don't already exist.
269	func ensureSelfSignedCert(dir string) (certFile, keyFile string, err error) {
270		if err = os.MkdirAll(dir, 0700); err != nil {
271			return
272		}
273		certFile = filepath.Join(dir, "cert.pem")
274		keyFile = filepath.Join(dir, "key.pem")
275	
276		// Re-use existing pair if both files are present and cert is still valid.
277		if _, e1 := os.Stat(certFile); e1 == nil {
278			if _, e2 := os.Stat(keyFile); e2 == nil {
279				if pair, e3 := tls.LoadX509KeyPair(certFile, keyFile); e3 == nil {
280					leaf, e4 := x509.ParseCertificate(pair.Certificate[0])
281					if e4 == nil && time.Now().Before(leaf.NotAfter.Add(-24*time.Hour)) {
282						return certFile, keyFile, nil
283					}
284				}
285			}
286		}
287	
288		// Generate new key + cert.
289		key, e := ecdsa.GenerateKey(elliptic.P256(), rand.Reader)
290		if e != nil {
291			err = e
292			return
293		}
294		serial, _ := rand.Int(rand.Reader, new(big.Int).Lsh(big.NewInt(1), 128))
295		tmpl := &x509.Certificate{
296			SerialNumber: serial,
297			Subject:      pkix.Name{CommonName: "ddx-server"},
298			NotBefore:    time.Now().Add(-time.Minute),
299			NotAfter:     time.Now().Add(10 * 365 * 24 * time.Hour),
300			KeyUsage:     x509.KeyUsageKeyEncipherment | x509.KeyUsageDigitalSignature,
301			ExtKeyUsage:  []x509.ExtKeyUsage{x509.ExtKeyUsageServerAuth},
302			IPAddresses:  []net.IP{net.ParseIP("127.0.0.1"), net.ParseIP("0.0.0.0")},
303			DNSNames:     []string{"localhost"},
304		}
305		certDER, e := x509.CreateCertificate(rand.Reader, tmpl, tmpl, &key.PublicKey, key)
306		if e != nil {
307			err = e
308			return
309		}
310	
311		cf, e := os.OpenFile(certFile, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0600)
312		if e != nil {
313			err = e
314			return
315		}
316		_ = pem.Encode(cf, &pem.Block{Type: "CERTIFICATE", Bytes: certDER})
317		_ = cf.Close()
318	
319		kf, e := os.OpenFile(keyFile, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0600)
320		if e != nil {
321			err = e
322			return
323		}
324		keyDER, _ := x509.MarshalECPrivateKey(key)
325		_ = pem.Encode(kf, &pem.Block{Type: "EC PRIVATE KEY", Bytes: keyDER})
326		_ = kf.Close()
327	
328		return certFile, keyFile, nil
329	}
