360	// tsnetMiddleware wraps the handler to inject Tailscale identity context and
361	// mark requests as coming from the tailnet (for dispatch endpoint access).
362	func tsnetMiddleware(ts *tsnet.Server, next http.Handler) http.Handler {
363		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
364			lc, err := ts.LocalClient()
365			if err == nil {
366				who, err := lc.WhoIs(r.Context(), r.RemoteAddr)
367				if err == nil && who != nil {
368					// Log caller identity for audit
369					login := who.UserProfile.LoginName
370					node := who.Node.ComputedName
371					r.Header.Set("X-Tailscale-User", login)
372					r.Header.Set("X-Tailscale-Node", node)
373					// Mark request as trusted tailnet peer so dispatch endpoints allow it
374					r = r.WithContext(context.WithValue(r.Context(), tsnetTrustedKey{}, true))
375				}
376			}
377			next.ServeHTTP(w, r)
378		})
379	}
